var expect = require('expect.js');
var RuleProject = require('../../res/page/ruleproject/ruleproject');

describe('sqlscan-ruleproject', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init RuleProject()', function(){
    it('init RuleProject', function(done){
      var ruleproject = RuleProject._create({
        events : {
          'aftercomplete' : function(){
            expect(ruleproject).to.be.ok();
            var projectname = this.query('combobox[name=projectname]');
            expect(projectname).to.be.ok();
          },
          'afterruleprojectlistload' : function(){
            var projectlist = this.query('list[name="ruleprojectlist"]');
            expect(projectlist).to.be.ok();
            expect(projectlist.data.records.length).to.eql(6);
            done();
          },
          'afterruleprojectsload' : function(){
            var projectname = this.query('combobox[name=projectname]');
            expect(projectname.store.data.records.length).to.eql(7);
          }
        }
      });
    });
  });
  describe('#searchRules events', function(){
    it('searchRules', function(done){
      var ruleproject = RuleProject._create({
        events : {
          'aftercomplete' : function(){
            var btnSearch = this.query('button[name="btnSearch"]');
            btnSearch.emit('click');
            done();
          },
          'afterruleprojectlistload' : function(){
            var projectlist = this.query('list[name="ruleprojectlist"]');
            expect(projectlist).to.be.ok();
            expect(projectlist.data.records.length).to.eql(6);
          }
        }
      });
    });
  });
  describe('#rowClickEvent events', function(){
    it('rowClickEvent', function(done){
      var ruleproject = RuleProject._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            var projectlist = _self.query('list[name="ruleprojectlist"]');
            expect(projectlist).to.be.ok();
            var row = $('.ruleproject-list', projectlist.el).eq(0);
            row.trigger({
              type : 'click',
              target : $('.btnEnableRule', row)
            });
            expect(this.checkUpdateRule).not.to.be.ok();
            row.trigger({
              type : 'click',
              target : $('.btnDisableRule', row)
            });
            done();
          },
          'afterenableprojectrule' : function(){
            var projectlist = this.query('list[name="ruleprojectlist"]');
            expect(projectlist.data.records.length).to.be(6);
            var status = this.getActiveStatus();
            expect(status).to.be(0);
          },
          'afterdisableprojectrule' : function(){
            var projectlist = this.query('list[name="ruleprojectlist"]');
            expect(projectlist.data.records.length).to.be(6);
            var status = this.getActiveStatus();
            expect(status).to.be(1);
          }
        }
      });
    });
  });
  describe('#tabclick events', function(){
    it('tabclick', function(done){
      var ruleproject = RuleProject._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            this.on('afterprojectlistload', function(){
              var projectlist = _self.query('list[name="ruleprojectlist"]');
              expect(projectlist).to.be.ok();
              expect(projectlist.data.records.length).to.be(6);
            });
            var ftab = $('.ruleprojectlist-tab', this.el).children("span:first");
            var stab = $('.ruleprojectlist-tab', this.el).children("span:last");
            ftab.trigger('click');
            expect(ftab[0].className).to.be('ruleprojectlist-tab-active');
            expect(stab[0].className).to.be('ruleprojectlist-tab-deactive');
            stab.trigger('click');
            expect(ftab[0].className).to.be('ruleprojectlist-tab-deactive');
            expect(stab[0].className).to.be('ruleprojectlist-tab-active');
            done();
          }
        }
      });
    });
  });
});